payload.raw:
{
  "layout": "image-text",
  "title": "创新技术：多模态人机交互系统",
  "subtitle": "",
  "body": [
    {
      "type": "bullet",
      "items": [
        "构建“感知-意图-反馈”闭环理论模型，融合肌电、弯曲度、IMU等多源信号，实现交互意图精准解析与实时反馈。",
        "采用自主设计的轻量化通信协议，深度适配PICO、Unity中国版等国产XR生态，降低对接开发成本，响应“生态封闭”痛点。",
        "全栈技术链贯通硬件感知、边缘计算与云端协同，形成软硬一体、开放兼容的技术底座。",
        "核心理论与系统架构发表于语音与信号处理领域顶会ICASSP，获审稿人“为多模态交互提供可复现范式”的高度评价。"
      ]
    }
  ],
  "image": {
    "prompt": "A detailed technical architecture diagram illustrating a multimodal human-computer interaction system. The diagram shows a closed-loop model with sections labeled 'Perception', 'Intention', and 'Feedback'. Arrows flow between these sections, indicating data from multiple sources like EMG sensors, bend sensors, and IMUs feeding into a central 'Dynamic Intention Inference Engine'. The diagram also includes layers for hardware, edge computing, and cloud collaboration, with icons representing sensors, algorithms, and communication protocols.",
    "alt": "多模态人机交互系统“感知-意图-反馈”闭环技术框架图"
  }
}

